def repeat(n):
    def deco(f):
        def w(*a):
            return [f(*a) for _ in range(n)]
        return w
    return deco
@repeat(3)
def hi():
    return 'hi'
print(hi())

def prefix(p):
    def deco(f):
        def w(s):
            return p + f(s)
        return w
    return deco
@prefix('>> ')
def shout(s):
    return s.upper()
print(shout('go'))

